const now = new Date();
const ksaHour = (now.getUTCHours() + 3) % 24; 
const day = now.getDay(); 


const forceOpen = true; 

let marketStatus = "open";

if (!forceOpen) {
    if (day === 6 || day === 0) {
        marketStatus = "weekend_closed";
    } else if (ksaHour >= 1 && ksaHour < 2) {
        marketStatus = "daily_closed";
    }
}

return { 
    marketStatus: marketStatus,
    shouldSend: true 
};

// 1. Retrieve persistent workflow data for state tracking
const staticData = $getWorkflowStaticData('global');

const keys = ['max24', 'min24', 'max22', 'min22', 'max21', 'min21', 'max18', 'min18'];
keys.forEach(key => {
    if (!staticData[key]) staticData[key] = key.includes('min') ? 9999 : 0;
});
if (!staticData.yesterdayClose24) staticData.yesterdayClose24 = 0;

// 2. Extract and validate input data
const items = $input.all();
if (!items || items.length === 0 || !items[0].json.price_gram_24k) {
    throw new Error("Invalid or empty data received from API.");
}

const data = items[0].json;
const prices = {
    "24": parseFloat(data.price_gram_24k),
    "22": parseFloat(data.price_gram_22k),
    "21": parseFloat(data.price_gram_21k),
    "18": parseFloat(data.price_gram_18k)
};

// 3. Update rolling maximum/minimum (With Zero-Check protection)
Object.keys(prices).forEach(karat => {
    const p = prices[karat];
    if (p > 0) { 
        if (p > staticData['max' + karat]) staticData['max' + karat] = p;
        if (p < staticData['min' + karat]) staticData['min' + karat] = p;
    }
});

// 4. Time and Status
const openTime = data.open_time || Math.floor(Date.now() / 1000);
const dateObj = new Date(openTime * 1000);
const ksaHour = (dateObj.getUTCHours() + 3) % 24;

if (staticData.yesterdayClose24 === 0 && prices["24"] > 0) staticData.yesterdayClose24 = prices["24"];
const status = prices["24"] >= staticData.yesterdayClose24 ? "Bullish 冒聼聼垄" : "Bearish 冒聼聰麓";

// 5. Output Logic
if (ksaHour === 23) {
    // End of day: prepare summary and reset
    const summary = { type: "summary" };
    keys.forEach(k => summary[k] = staticData[k].toFixed(2));
    keys.forEach(k => staticData[k] = k.includes('min') ? 9999 : 0);
    return [{ json: summary }];
} else {
    // Live update: return prices + current rolling max/min stats
    return [{
        json: {
            type: "live",
            price24: prices["24"].toFixed(2),
            price22: prices["22"].toFixed(2),
            price21: prices["21"].toFixed(2),
            price18: prices["18"].toFixed(2),
            // 脵聠脵聟脴卤脴卤 脴搂脵聞脵聙 max/min 脴搂脵聞脴颅脴搂脵聞脵聤脴漏 脵聡脵聠脴搂 脵聞脴露脵聟脴搂脵聠 脴鹿脴炉脵聟 脴赂脵聡脵聢脴卤 脴搂脵聞脵聛脴卤脴搂脴潞脴搂脴陋 脵聛脵聤 脴搂脵聞脴卤脴鲁脴搂脵聞脴漏
            max24: staticData.max24.toFixed(2), min24: staticData.min24.toFixed(2),
            max22: staticData.max22.toFixed(2), min22: staticData.min22.toFixed(2),
            max21: staticData.max21.toFixed(2), min21: staticData.min21.toFixed(2),
            max18: staticData.max18.toFixed(2), min18: staticData.min18.toFixed(2),
            time: dateObj.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: true }),
            status: status
        }
    }];
}

